                "import torch",
                "",
                "def train_epoch(model, loader, optimizer, criterion, device=\"cpu\"):",
                "    model.train()",
                "    total = 0.0",
                "    for x, y in loader:",
                "        x, y = x.to(device), y.to(device)",
                "        optimizer.zero_grad()",
                "        logits = model(x)",
                "        loss = criterion(logits, y)",
                "        loss.backward()",
                "        optimizer.step()",
                "        total += loss.item()",
                "    return total / max(len(loader), 1)",
